import type { SyntaxNodeRef } from '@lezer/common';

import type { NumberFormatParser } from '../../../../parser/getNumberParser.js';
import type { ConvertedLezerNode } from '../../../../types/conversion-utils.js';
import type {
  FilterFieldBigIntNode,
  FilterFieldNumberNode,
  FilterFieldStringNode,
} from '../../../../types/tree-nodes.js';
import { getTextFromRange } from '../../../get-text.js';

/**
 * Convert a number node.
 * @internal
 */
export function convertNumber(
  node: SyntaxNodeRef,
  doc: string,
  numberParser: NumberFormatParser,
): ConvertedLezerNode<
  FilterFieldNumberNode | FilterFieldBigIntNode | FilterFieldStringNode
> {
  const { from, to } = node;
  const textValue = getTextFromRange(node, doc);

  const parsedNumber = numberParser.parse(textValue);
  let convertedNode:
    | FilterFieldNumberNode
    | FilterFieldBigIntNode
    | FilterFieldStringNode = {
    type: 'Number',
    textValue,
    value: parsedNumber,
    range: { from, to },
  };

  // Check if the parsed number exceeds MAX_SAFE_INTEGER for BigInt conversion and no
  // decimal point. If there is a decimal point, treat it as a string as BigInt cannot
  // handle decimals.
  if (parsedNumber > Number.MAX_SAFE_INTEGER) {
    if (textValue.includes('.')) {
      convertedNode = {
        ...convertedNode,
        type: 'String',
        value: textValue,
      };
    } else {
      convertedNode = {
        ...convertedNode,
        type: 'BigInt',
        value: BigInt(textValue).toString(),
      };
    }
  }
  return { convertedNode, errors: [] };
}
